package com.datamaster.module.assets.controller.admin.discovery;import cn.hutool.core.date.DateUtil;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import org.quartz.SchedulerException;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import com.datamaster.common.annotation.Log;import com.datamaster.common.core.controller.BaseController;import com.datamaster.common.core.domain.AjaxResult;import com.datamaster.common.core.domain.CommonResult;import com.datamaster.common.core.page.PageParam;import com.datamaster.common.core.page.PageResult;import com.datamaster.common.core.page.TableDataInfo;import com.datamaster.common.enums.BusinessType;import com.datamaster.common.utils.object.BeanUtils;import com.datamaster.common.utils.poi.ExcelUtil;import com.datamaster.module.assets.controller.admin.discovery.vo.AssetsDiscoveryTaskPageReqVO;import com.datamaster.module.assets.controller.admin.discovery.vo.AssetsDiscoveryTaskRespVO;import com.datamaster.module.assets.controller.admin.discovery.vo.AssetsDiscoveryTaskSaveReqVO;import com.datamaster.module.assets.convert.discovery.AssetsDiscoveryTaskConvert;import com.datamaster.module.assets.dal.dataobject.discovery.AssetsDiscoveryTaskDO;import com.datamaster.module.assets.service.discovery.IAssetsDiscoveryTaskService;import com.datamaster.quartz.domain.SysJobLog;import com.datamaster.quartz.service.ISysJobLogService;import javax.annotation.Resource;import javax.servlet.http.HttpServletResponse;import javax.validation.Valid;import java.util.Arrays;import java.util.List;/** * 数据发现任务Controller * * @author DATAMASTER * @date 2025-02-11 */@Tag(name = "数据发现任务")@RestController@RequestMapping("/ast/discoveryTask")@Validated
public class AssetsDiscoveryTaskController extends BaseController {    @Resource    private IAssetsDiscoveryTaskService AssetsDiscoveryTaskService;    @Resource    private ISysJobLogService jobLogService;    @Operation(summary = "查询数据发现任务列表")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsDiscoveryTaskRespVO>> list(AssetsDiscoveryTaskPageReqVO AssetsDiscoveryTask) {        PageResult<AssetsDiscoveryTaskDO> page = AssetsDiscoveryTaskService.getDaDiscoveryTaskPage(AssetsDiscoveryTask);        return CommonResult.success(BeanUtils.toBean(page, AssetsDiscoveryTaskRespVO.class));    }    @Operation(summary = "查询数据发现任务列表")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:list')")    @GetMapping("/getDaDiscoveryTaskListPage")    public CommonResult<PageResult<AssetsDiscoveryTaskRespVO>> getDaDiscoveryTaskListPage(AssetsDiscoveryTaskPageReqVO AssetsDiscoveryTask) {        return CommonResult.success(AssetsDiscoveryTaskService.getDaDiscoveryTaskListPage(AssetsDiscoveryTask));    }    @Operation(summary = "导出数据发现任务列表")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:export')")    @Log(title = "数据发现任务", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsDiscoveryTaskPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsDiscoveryTaskDO> list = (List<AssetsDiscoveryTaskDO>) AssetsDiscoveryTaskService.getDaDiscoveryTaskPage(exportReqVO).getRows();        ExcelUtil<AssetsDiscoveryTaskRespVO> util = new ExcelUtil<>(AssetsDiscoveryTaskRespVO.class);        util.exportExcel(response, AssetsDiscoveryTaskConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据发现任务列表")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:import')")    @Log(title = "数据发现任务", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsDiscoveryTaskRespVO> util = new ExcelUtil<>(AssetsDiscoveryTaskRespVO.class);        List<AssetsDiscoveryTaskRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsDiscoveryTaskService.importDaDiscoveryTask(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据发现任务详细信息")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsDiscoveryTaskRespVO> getInfo(@PathVariable("id") Long id) {        return CommonResult.success(AssetsDiscoveryTaskService.getDaDiscoveryTaskById(id));    }    /**     * 查询定时任务调度日志列表     */    @PreAuthorize("@ss.hasPermi('da:discoveryTask:list')")    @GetMapping("/jobLog/list")    public TableDataInfo jobList(SysJobLog sysJobLog)    {        startPage();        List<SysJobLog> list = jobLogService.selectJobLogList(sysJobLog);        return getDataTable(list);    }    /**     * 根据调度编号获取详细信息     */    @PreAuthorize("@ss.hasPermi('da:discoveryTask:query')")    @GetMapping(value = "/jobLog/{jobLogId}")    public AjaxResult getJobLogInfo(@PathVariable Long jobLogId)    {        return success(jobLogService.selectJobLogById(jobLogId));    }    /**     * 清空定时任务调度日志     */    @PreAuthorize("@ss.hasPermi('da:discoveryTask:remove')")    @Log(title = "调度日志", businessType = BusinessType.CLEAN)    @DeleteMapping("/jobLog/clean")    public AjaxResult clean()    {        jobLogService.cleanJobLog();        return success();    }    @Operation(summary = "新增数据发现任务")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:add')")    @Log(title = "数据发现任务", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsDiscoveryTaskSaveReqVO AssetsDiscoveryTask) {        AssetsDiscoveryTask.setCreatorId(getUserId());        AssetsDiscoveryTask.setCreateBy(getNickName());        AssetsDiscoveryTask.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsDiscoveryTaskService.createDaDiscoveryTask(AssetsDiscoveryTask));    }    @Operation(summary = "修改数据发现任务")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:edit')")    @Log(title = "数据发现任务", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsDiscoveryTaskSaveReqVO AssetsDiscoveryTask) {        AssetsDiscoveryTask.setUpdatorId(getUserId());        AssetsDiscoveryTask.setUpdateBy(getNickName());        AssetsDiscoveryTask.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsDiscoveryTaskService.updateDaDiscoveryTask(AssetsDiscoveryTask));    }    @Operation(summary = "删除数据发现任务")    @PreAuthorize("@ss.hasPermi('da:discoveryTask:remove')")    @Log(title = "数据发现任务", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsDiscoveryTaskService.removeDaDiscoveryTask(Arrays.asList(ids)));    }    @Log(title = "定时任务", businessType = BusinessType.UPDATE)    @PutMapping("/runDaDiscoveryTask/{id}")    public AjaxResult runDaDiscoveryTask(@PathVariable("id") Long id) throws SchedulerException    {        boolean result = AssetsDiscoveryTaskService.runDaDiscoveryTask(id);        return result ? success() : error("任务不存在或已过期！");    }    @Log(title = "触发一次定时任务", businessType = BusinessType.UPDATE)    @PutMapping("/startDaDiscoveryTask/{id}")    public AjaxResult startDaDiscoveryTask(@PathVariable("id") Long id)    {        return AssetsDiscoveryTaskService.startDaDiscoveryTask(id);    }    @Log(title = "数据发现任务状态修改", businessType = BusinessType.UPDATE)    @PreAuthorize("@ss.hasPermi('da:discoveryTask:edit')")    @PostMapping("/updateDaDiscoveryTaskStatus")    public AjaxResult updateDaDiscoveryTaskStatus(@RequestBody AssetsDiscoveryTaskSaveReqVO AssetsDiscoveryTask) throws SchedulerException    {        boolean result = AssetsDiscoveryTaskService.updateDaDiscoveryTaskStatus(AssetsDiscoveryTask);        return result ? success() : error("任务不存在或已过期！");    }    @Log(title = "数据发现任务状态修改", businessType = BusinessType.UPDATE)    @PreAuthorize("@ss.hasPermi('da:discoveryTask:edit')")    @PostMapping("/updateDaDiscoveryTaskCronExpression")    public AjaxResult updateDaDiscoveryTaskCronExpression(@RequestBody AssetsDiscoveryTaskSaveReqVO AssetsDiscoveryTask) throws SchedulerException    {        boolean result = AssetsDiscoveryTaskService.updateDaDiscoveryTaskCronExpression(AssetsDiscoveryTask);        return result ? success() : error("任务不存在或已过期！");    }}